from flask import Flask, jsonify
import traceback

app = Flask(__name__)

@app.errorhandler(Exception)
def handle_error(e):
    error_details = traceback.format_exc()
    return jsonify({
        'error': str(e),
        'traceback': error_details
    }), 500
